def read_jsonl(path: str) -> List[Dict[str, Any]]:
    docs: List[Dict[str, Any]] = []
    with open(path, "r", encoding="utf-8") as f:
        for i, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except Exception as e:
                raise ValueError(f"Invalid JSON on line {i}: {e}") from e
            if not isinstance(obj, dict):
                raise ValueError(f"JSONL line {i} must be an object")
            docs.append(obj)
    return docs


def main(argv: Optional[List[str]] = None) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)

    app = ESApp(es_url=args.es)

    try:
        if args.cmd == "ping":
            json_print({"ok": app.ping(), "es": args.es})
            return 0

        if args.cmd == "init":
            app.ensure_indices(doc_index=args.doc_index, log_index=args.log_index)
            json_print({"ok": True, "doc_index": args.doc_index, "log_index": args.log_index})
            return 0

        if args.cmd == "index-doc":
            app.ensure_indices(doc_index=args.doc_index, log_index=args.log_index)
            metadata = coerce_json_or_text(args.metadata)
            if not isinstance(metadata, dict):
                raise ValueError("--metadata must be a JSON object")
            doc = {
                "@timestamp": utc_now_iso(),
                "title": args.title,
                "content": args.content,
                "tags": args.tags,
                "source": args.source,
                "metadata": metadata,
            }
            res = app.index_document(
                index=args.doc_index,
                doc=doc,
                doc_id=args.id,
                refresh=args.refresh,
                pipeline=args.pipeline or "",
            )
            json_print(res)
            return 0

        if args.cmd == "bulk-index-docs":
            app.ensure_indices(doc_index=args.doc_index, log_index=args.log_index)
            docs = read_jsonl(args.path)
            ok, err = app.bulk_index(
                index=args.doc_index,
                docs=docs,
                id_field=args.id_field,
                refresh=args.refresh,
                pipeline=args.pipeline or "",
            )
            json_print({"ok": True, "indexed": ok, "errors": err})
            return 0

        if args.cmd == "search-docs":
            filters = parse_kv_pairs(args.filter)
            time_range = (args.start, args.end) if (args.start or args.end) else None
            res = app.search(
                index=args.doc_index,
                query=args.query,
                fields=args.fields,
                filters=filters,
                from_=args.from_,
                size=args.size,
                sort=args.sort,
                time_range=time_range,
            )
            json_print(res)
            return 0

        if args.cmd == "log":
            app.ensure_indices(doc_index=args.doc_index, log_index=args.log_index)
            extra_fields = parse_kv_pairs(args.field)
            msg_obj = coerce_json_or_text(args.message)
            if isinstance(msg_obj, dict):
                message = msg_obj.get("message") or json.dumps(msg_obj, ensure_ascii=False)
                if "fields" in msg_obj and isinstance(msg_obj["fields"], dict):
                    merged = dict(msg_obj["fields"])
                    merged.update(extra_fields)
                    extra_fields = merged
                for k in ("level", "service", "host", "env", "trace_id", "span_id", "logger"):
                    if k in msg_obj and getattr(args, k.replace("_", "-"), None) is None:
                        pass
            else:
                message = str(msg_obj)

            res = app.log_event(
                index=args.log_index,
                message=message,
                level=args.level,
                service=args.service,
                host=args.host,
                env=args.env,
                trace_id=args.trace_id,
                span_id=args.span_id,
                logger=args.logger,
                fields=extra_fields if extra_fields else None,
                refresh=args.refresh,
                pipeline=args.pipeline or "",
            )
            json_print(res)
            return 0

        if args.cmd == "search-logs":
            filters = parse_kv_pairs(args.filter)
            time_range = (args.start, args.end) if (args.start or args.end) else None
            res = app.search(
                index=args.log_index,
                query=args.query,
                fields=args.fields,
                filters=filters,
                from_=args.from_,
                size=args.size,
                sort=args.sort,
                time_range=time_range,
            )
            json_print(res)
            return 0

        if args.cmd == "agg-logs":
            res = app.aggregate_logs(
                index=args.log_index,
                start=args.start,
                end=args.end,
                service=args.service,
                level=args.level,
                env=args.env,
                interval=args.interval,
                top_services=args.top_services,
                top_messages=args.top_messages,
                query=args.query,
            )
            json_print(res)
            return 0

        raise ValueError(f"Unknown command: {args.cmd}")

    except (TransportError, NotFoundError, ConflictError) as e:
        json_print({"ok": False, "error": str(e), "type": e.__class__.__name__})
        return 2
    except Exception as e:
        json_print({"ok": False, "error": str(e), "type": e.__class__.__name__})
        return 1


if __name__ == "__main__":
    raise SystemExit(main())